#include <bits/stdc++.h>
using namespace std;

long long a[25][25];

int main() {
    int n;
    cin >> n;
    for (int i = 0; i < n; i++) a[i][0] = 1;
    cout << "1\n";
    for (int i = 1; i < n; i++) {
        cout << "1 ";
        for (int j = 1; j <= i; j++) {
            a[i][j] = a[i - 1][j] + a[i - 1][j - 1];
            cout << a[i][j] << ' ';
        }
        cout << endl;
    }
    return 0;
}
